  ('aviation-f975d768-moex-00084', 'aviation-f975d768', 'aviation-f975d768-moex-112-7bf35b0f', 'sub-aviation-f975d768-05', NULL, 'single_choice', '依司法院釋字第791號解釋，下列敘述何者錯誤？', '["以刑罰制裁通姦及相姦行為，其目的在於約束配偶雙方履行婚姻忠誠義務，以維護婚姻制度及個別 婚姻之存續，洵屬正當", "有配偶而與人通姦者，處1年以下有期徒刑之規定，涉及憲法第22條保障之性自主權", "刑法通姦罪規定對性自主權之限制是否合於比例原則，應受較嚴格之審查", "對配偶撤回通姦罪告訴，其效力不及於相姦人之規定，與憲法第7條平等權之意旨並無違背"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:09+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "402", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "航空通訊"}'::jsonb, NULL),
